const resp = $.steps.readSheet.response || {};
const values = resp.values || [];

if (values.length === 0) {
  return { dataText: 'No data found in the spreadsheet.', headers: [], rowCount: 0, colCount: 0, hasData: false };
}

const headers = values[0] || [];
const dataRows = values.slice(1);

let dataText = 'SPREADSHEET DATA\n';
dataText += 'Columns: ' + headers.join(', ') + '\n';
dataText += 'Total rows: ' + dataRows.length + '\n\n';
dataText += 'HEADER ROW: ' + headers.join(' | ') + '\n';
dataText += '-'.repeat(60) + '\n';

dataRows.slice(0, 200).forEach((row, i) => {
  const paddedRow = headers.map((h, j) => (row[j] !== undefined ? row[j] : ''));
  dataText += 'Row ' + (i + 1) + ': ' + paddedRow.join(' | ') + '\n';
});

if (dataRows.length > 200) {
  dataText += '\n... (' + (dataRows.length - 200) + ' more rows not shown)\n';
}

const colStats = headers.map((h, j) => {
  const colValues = dataRows.map(r => r[j]).filter(v => v !== undefined && v !== '');
  const numValues = colValues.filter(v => !isNaN(Number(v))).map(Number);
  const stat = { column: h, nonEmpty: colValues.length, uniqueValues: new Set(colValues).size };
  if (numValues.length > 0) {
    stat.min = Math.min(...numValues);
    stat.max = Math.max(...numValues);
    stat.avg = (numValues.reduce((a, b) => a + b, 0) / numValues.length).toFixed(2);
    stat.isNumeric = true;
  }
  return stat;
});

dataText += '\nCOLUMN STATISTICS:\n';
colStats.forEach(s => {
  dataText += '- ' + s.column + ': ' + s.nonEmpty + ' values, ' + s.uniqueValues + ' unique';
  if (s.isNumeric) dataText += ', range ' + s.min + '-' + s.max + ', avg ' + s.avg;
  dataText += '\n';
});

return { dataText, headers, rowCount: dataRows.length, colCount: headers.length, hasData: true, colStats };

const question = $.input.question;
const data = $.steps.formatData.output;

let prompt = 'You are a data analyst assistant. A user has a Google Sheets spreadsheet and wants to ask questions about their data. Analyze the data provided and answer the question thoroughly.\n\n';
prompt += 'USER QUESTION: ' + question + '\n\n';
prompt += data.dataText + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Answer the question based on the actual data provided\n';
prompt += '- Include specific numbers, calculations, and data references\n';
prompt += '- If the question requires aggregation (sum, average, count, etc.), perform the calculation\n';
prompt += '- Mention any data quality issues or caveats\n';
prompt += '- Format numbers with appropriate precision\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "answer": "detailed answer to the question",\n';
prompt += '  "keyFindings": ["finding 1", "finding 2"],\n';
prompt += '  "dataPoints": [{ "label": "metric name", "value": "metric value" }],\n';
prompt += '  "chartSuggestion": "what kind of chart would best visualize this data (optional)",\n';
prompt += '  "summary": "one-line summary"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, keyFindings: [], dataPoints: [], summary: 'See raw answer' }; }

const ai = $.steps.parseAI.output;
const question = $.input.question;
const data = $.steps.formatData.output;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Sheets Data Analysis', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Question:* ' + question } });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Analyzing ' + data.rowCount + ' rows x ' + data.colCount + ' columns' }] });
blocks.push({ type: 'divider' });

const answerText = (ai.answer || 'No answer generated.').slice(0, 1800);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Answer:*\n' + answerText } });

if (ai.keyFindings && ai.keyFindings.length > 0) {
  blocks.push({ type: 'divider' });
  let findingsText = '*Key Findings:*\n';
  ai.keyFindings.forEach((f, i) => { findingsText += (i + 1) + '. ' + f + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: findingsText.slice(0, 1800) } });
}

if (ai.dataPoints && ai.dataPoints.length > 0) {
  const fields = ai.dataPoints.slice(0, 10).map(dp => ({ type: 'mrkdwn', text: '*' + dp.label + '*\n' + dp.value }));
  while (fields.length > 0) {
    blocks.push({ type: 'section', fields: fields.splice(0, 10) });
  }
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Google Sheets + Claude AI' }] });

const fallbackText = 'Sheets Analysis: ' + (ai.summary || question);
return { blocks, fallbackText };
